// 业务核心代码（新增）：冷启动时恢复 usage 快照，并补偿后台停留时间。
- (void)loadUsageState {
    NSString *filePath = [self usageStateFilePath];
    if (![NSFileManager.defaultManager fileExistsAtPath:filePath]) {
        return;
    }

    NSError *error = nil;
    NSData *data = [NSData dataWithContentsOfFile:filePath options:0 error:&error];
    if (error || !data) {
        return;
    }

    id json = [NSJSONSerialization JSONObjectWithData:data options:0 error:&error];
    if (error || ![json isKindOfClass:[NSDictionary class]]) {
        return;
    }

    NSDictionary *snapshot = (NSDictionary *)json;
    self.appUsedTimeInSecond = [snapshot[@"a"] unsignedIntValue];
    self.vappUsedTimeInSecond = [snapshot[@"v"] unsignedIntValue];

    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
    NSNumber *backgroundTimeNum = snapshot[@"b"];
    if ([backgroundTimeNum isKindOfClass:[NSNumber class]]) {
        CFAbsoluteTime rawDelta = floor(now - backgroundTimeNum.doubleValue);
        if (rawDelta > 0) {
            uint32_t delta = (uint32_t)MIN(rawDelta, (CFAbsoluteTime)UINT32_MAX);
            self.appUsedTimeInSecond += delta;
            if ([snapshot[@"br"] boolValue]) {
                self.vappUsedTimeInSecond += delta;
            }
        }
    }

    self.backgroundEnterTime = 0;
    self.backgroundEnterVappRunning = NO;
    self.lastUsageCheckpoint = now;
    self.lastKnownVappRunning = vapp_is_running();
    self.usageCheckpointInitialized = YES;

    [NSFileManager.defaultManager removeItemAtPath:filePath error:nil];
}

