@implementation WBActionRequestManager

+ (instancetype)sharedManager {
    static id instance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[self alloc] init];
    });
    return instance;
}

- (void)enableEventActionRequest {
    self.eventActionRequestEnabled = TRUE;
}

- (void)handleActionModel:(WBBaseActionModel *)actionModel error:(NSError *)error defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    if (error) {
        if (defaultHandler) defaultHandler(nil);
        return;
    }
    if (!actionModel) return;
    [actionModel executeWithDefaultHandler:defaultHandler];
}

- (void)requestLaunchVappWithVapp:(WBVAppModel *)vapp defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    [[WBNetworkManager defaultManager] requestLaunchVappWithVapp:vapp callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
        [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
    }];
}

- (void)requestLaunchVappWithVappId:(NSInteger)vappId defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    [[WBNetworkManager defaultManager] requestLaunchVappWithVappId:vappId callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
        [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
    }];
}

- (void)requestReserveVappWithVappId:(NSInteger)vappId defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    [[WBNetworkManager defaultManager] requestReserveVappWithVappId:vappId callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
        [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
    }];
}

- (void)requestGetVappWithVappId:(NSInteger)vappId defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    [[WBNetworkManager defaultManager] requestGetVappWithVappId:vappId callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
        [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
    }];
}

- (void)requestCollectRewardOfRewardAd:(NSInteger)vappId defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    [[WBNetworkManager defaultManager] requestGetVappWithVappId:vappId callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
        [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
    }];
}

- (void)requestReportEventWithType:(WBActionRequestEventType)type defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    if (self.eventActionRequestEnabled) {
        [[WBNetworkManager defaultManager] requestReportEventWithType:type callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
            [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
        }];
    }
}

- (void)requestReportEventWithType:(WBActionRequestEventType)type data:(NSDictionary *)data defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    if (self.eventActionRequestEnabled) {
        [[WBNetworkManager defaultManager] requestReportEventWithType:type data:data callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
            [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
        }];
    }
}

- (void)requestFromShareReportEventWithType:(WBActionRequestEventType)type defaultHandler:(WBActionRequestDefaultHandler)defaultHandler {
    if (self.eventActionRequestEnabled) {
        [[WBNetworkManager defaultManager] requestReportEventWithType:type callback:^(WBBaseActionModel * _Nullable actionModel, NSError * _Nullable error) {
            if (error) {
                [SVProgressHUD showErrorWithStatus:error.localizedDescription];
                return;
            }
            [self handleActionModel:actionModel error:error defaultHandler:defaultHandler];
        }];
    }
